#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

/* Configuration Constants */
#define MAX_IPS 1000
#define MAX_IP_LENGTH 16
#define BASE_SCORE 50
#define HIGH_THRESHOLD 75
#define LOW_THRESHOLD 40

/* Threat Level Enumeration */
typedef enum {
    THREAT_UNKNOWN = 0,
    THREAT_BOTNET = 1,
    THREAT_MALWARE = 2,
    THREAT_PHISHING = 3,
    THREAT_SPAM = 4
} ThreatType;

/* Action Types */
typedef enum {
    ACTION_ALLOW = 0,
    ACTION_SCRUTINIZE = 1,
    ACTION_BLOCK = 2
} Action;

/* IP Reputation Entry */
typedef struct {
    char ip[MAX_IP_LENGTH];
    int score;
    ThreatType threat_level;
    int threat_confidence;
    bool is_trusted;
    int request_count;
    int blocked_count;
} IPRecord;

/* Data Center Traffic Request */
typedef struct {
    char source_ip[MAX_IP_LENGTH];
    char country_code[3];
    int failed_auths;
    int successful_auths;
    bool is_known_device;
    int behavior_deviation;  /* 0-100 */
} TrafficRequest;

/* Threat Intelligence Database */
typedef struct {
    char ip[MAX_IP_LENGTH];
    ThreatType type;
    int confidence;
} ThreatEntry;

/* Global State */
IPReputationSystem *system = NULL;

/* Initialize the reputation system */
typedef struct IPReputationSystem {
    IPRecord records[MAX_IPS];
    int record_count;
    ThreatEntry threats[50];
    int threat_count;
    int total_allowed;
    int total_blocked;
    int total_scrutinized;
} IPReputationSystem;

IPReputationSystem* init_system() {
    IPReputationSystem *sys = (IPReputationSystem*)malloc(sizeof(IPReputationSystem));
    sys->record_count = 0;
    sys->threat_count = 0;
    sys->total_allowed = 0;
    sys->total_blocked = 0;
    sys->total_scrutinized = 0;

    /* Populate sample threat intelligence */
    strcpy(sys->threats[0].ip, "192.168.1.100");
    sys->threats[0].type = THREAT_BOTNET;
    sys->threats[0].confidence = 95;

    strcpy(sys->threats[1].ip, "10.0.0.50");
    sys->threats[1].type = THREAT_MALWARE;
    sys->threats[1].confidence = 88;

    strcpy(sys->threats[2].ip, "203.0.113.25");
    sys->threats[2].type = THREAT_SPAM;
    sys->threats[2].confidence = 75;

    sys->threat_count = 3;

    return sys;
}

/* Check if IP is in threat database */
int check_threat_database(IPReputationSystem *sys, const char *ip) {
    for (int i = 0; i < sys->threat_count; i++) {
        if (strcmp(sys->threats[i].ip, ip) == 0) {
            return i;  /* Return index of threat */
        }
    }
    return -1;
}

/* Calculate reputation score for an IP */
int calculate_reputation_score(IPReputationSystem *sys, TrafficRequest *req) {
    int score = BASE_SCORE;

    /* Factor 1: Check threat intelligence */
    int threat_idx = check_threat_database(sys, req->source_ip);
    if (threat_idx >= 0) {
        score -= sys->threats[threat_idx].confidence / 2;  /* Up to -50 */
    }

    /* Factor 2: Authentication success rate */
    int total_auths = req->successful_auths + req->failed_auths;
    if (total_auths > 0) {
        double success_rate = (double)req->successful_auths / total_auths;
        score += (int)(success_rate * 15);
    }

    /* Factor 3: Failed authentication penalty */
    if (req->failed_auths > 10) {
        score -= 30;
    } else if (req->failed_auths > 5) {
        score -= 15;
    }

    /* Factor 4: Geographic risk assessment */
    if (strcmp(req->country_code, "US") == 0 || 
        strcmp(req->country_code, "UK") == 0 ||
        strcmp(req->country_code, "CA") == 0) {
        score += 10;  /* Trusted countries */
    } else if (strcmp(req->country_code, "RU") == 0 || 
               strcmp(req->country_code, "CN") == 0) {
        score -= 15;  /* High risk countries */
    }

    /* Factor 5: Known device bonus */
    if (req->is_known_device) {
        score += 15;
    }

    /* Factor 6: Behavioral deviation penalty */
    if (req->behavior_deviation > 80) {
        score -= 20;
    } else if (req->behavior_deviation > 50) {
        score -= 10;
    }

    /* Clamp to valid range */
    if (score < 0) score = 0;
    if (score > 100) score = 100;

    return score;
}

/* Determine action based on reputation score */
Action get_action_from_score(int score) {
    if (score >= HIGH_THRESHOLD) {
        return ACTION_ALLOW;
    } else if (score >= LOW_THRESHOLD) {
        return ACTION_SCRUTINIZE;
    } else {
        return ACTION_BLOCK;
    }
}

/* Process incoming traffic request */
void process_request(IPReputationSystem *sys, TrafficRequest *req) {
    int score = calculate_reputation_score(sys, req);
    Action action = get_action_from_score(score);

    /* Update statistics */
    switch (action) {
        case ACTION_ALLOW:
            sys->total_allowed++;
            printf("[ALLOW]  ");
            break;
        case ACTION_SCRUTINIZE:
            sys->total_scrutinized++;
            printf("[SCRUTINIZE] ");
            break;
        case ACTION_BLOCK:
            sys->total_blocked++;
            printf("[BLOCK]  ");
            break;
    }

    printf("IP: %-16s | Score: %3d/100 | Country: %s | Auth: %d/%d\n",
           req->source_ip, score, req->country_code, 
           req->successful_auths, req->failed_auths);
}

/* Print system statistics */
void print_statistics(IPReputationSystem *sys) {
    int total = sys->total_allowed + sys->total_blocked + sys->total_scrutinized;
    if (total == 0) return;

    printf("\n=== Traffic Protection Statistics ===\n");
    printf("Total Requests:    %d\n", total);
    printf("Allowed (High Rep): %d (%.1f%%)\n", 
           sys->total_allowed, (sys->total_allowed * 100.0) / total);
    printf("Scrutinized:        %d (%.1f%%)\n", 
           sys->total_scrutinized, (sys->total_scrutinized * 100.0) / total);
    printf("Blocked (Low Rep):  %d (%.1f%%)\n", 
           sys->total_blocked, (sys->total_blocked * 100.0) / total);
}

int main() {
    printf("========================================\n");
    printf("Data Center Reputation-Based Traffic Filter\n");
    printf("========================================\n\n");

    /* Initialize system */
    system = init_system();

    /* Simulate incoming traffic */
    TrafficRequest requests[] = {
        /* Legitimate high-reputation traffic */
        {"8.8.8.8", "US", 0, 100, true, 5},
        {"1.1.1.1", "US", 1, 50, true, 10},

        /* Known malicious IPs from threat database */
        {"192.168.1.100", "CN", 15, 2, false, 95},
        {"10.0.0.50", "RU", 20, 0, false, 90},

        /* Suspicious but not blacklisted */
        {"203.0.113.25", "RU", 8, 3, false, 60},

        /* Normal users */
        {"45.33.32.156", "DE", 2, 30, false, 20},
        {"185.220.101.1", "US", 0, 15, true, 15},

        /* Attack pattern - many failed auths */
        {"198.51.100.50", "CN", 25, 1, false, 85},
    };

    int num_requests = sizeof(requests) / sizeof(requests[0]);

    printf("Processing %d traffic requests...\n\n", num_requests);

    for (int i = 0; i < num_requests; i++) {
        process_request(system, &requests[i]);
    }

    /* Print final statistics */
    print_statistics(system);

    printf("\n=== Protection Active ===\n");

    free(system);
    return 0;
}
